# solution.py
"""
Team Collaboration Manager -- stdlib only, ASCII only, Python 3.12.

Design:
  - Single shared threading.RLock (RLock because public methods call each other).
  - _Context holds the lock, a global id counter, and the now() callable.
  - Six store objects (_UserStore, _ProjectStore, _TaskStore, _MessageStore,
    _PerformanceStore, _ReportStore) all receive the same _Context so their
    self._lock attributes are identical objects.
  - TeamCollaborationManager exposes stores as public attributes and delegates
    each public method to the relevant store (validation that spans two stores
    lives in the manager).
  - Every get_* / list_* returns a deep copy to guarantee isolation.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import List, Optional

# PDF xref free-list head: offset 0, generation 65535, type 'f'
_PDF_XREF_FREE_HEAD = b"0000000000 65535 f \n"

# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------

class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------

class TeamCollaborationError(Exception):
    """Base for all domain errors."""


class ValidationError(TeamCollaborationError):
    pass


class NotFoundError(TeamCollaborationError):
    pass


class AuthorizationError(TeamCollaborationError):
    pass


class DuplicateError(TeamCollaborationError):
    pass


class ConflictError(TeamCollaborationError):
    pass


# ---------------------------------------------------------------------------
# Dataclasses
# ---------------------------------------------------------------------------

@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    status: TaskStatus = TaskStatus.NOT_STARTED
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Shared context
# ---------------------------------------------------------------------------

class _Context:
    """Holds the single shared RLock, global id counter, and now callable."""

    def __init__(self, now_fn):
        self.lock = threading.RLock()
        self._counter = 0
        self.now = now_fn

    def next_id(self):
        """Increment and return next id. Caller must hold the lock."""
        self._counter += 1
        return self._counter


# ---------------------------------------------------------------------------
# Stores
# ---------------------------------------------------------------------------

class _UserStore:
    def __init__(self, ctx):
        self._ctx = ctx
        self._lock = ctx.lock
        self._users = {}          # id -> User
        self._by_username = {}    # username -> id
        self._by_email = {}       # email -> id

    def register(self, username, email, role):
        with self._lock:
            if not username or not username.strip():
                raise ValidationError("username is required")
            if not email or "@" not in email:
                raise ValidationError("valid email required")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole instance")
            if username in self._by_username:
                raise DuplicateError("username already taken")
            if email in self._by_email:
                raise DuplicateError("email already registered")
            uid = self._ctx.next_id()
            user = User(id=uid, username=username, email=email, role=role,
                        created_at=self._ctx.now())
            self._users[uid] = user
            self._by_username[username] = uid
            self._by_email[email] = uid
            return copy.deepcopy(user)

    def get(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user {0} not found".format(user_id))
            return copy.deepcopy(self._users[user_id])

    def list_all(self):
        with self._lock:
            return [copy.deepcopy(u)
                    for u in sorted(self._users.values(), key=lambda u: u.id)]

    def update(self, user_id, username=None, email=None, role=None):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user {0} not found".format(user_id))
            user = self._users[user_id]
            # Validate new email format first
            if email is not None and (not email or "@" not in email):
                raise ValidationError("valid email required")
            # Check uniqueness only when the value actually changes
            if username is not None and username != user.username:
                if username in self._by_username:
                    raise DuplicateError("username already taken")
            if email is not None and email != user.email:
                if email in self._by_email:
                    raise DuplicateError("email already registered")
            # Apply changes
            if username is not None:
                del self._by_username[user.username]
                user.username = username
                self._by_username[username] = user_id
            if email is not None:
                del self._by_email[user.email]
                user.email = email
                self._by_email[email] = user_id
            if role is not None:
                user.role = role
            return copy.deepcopy(user)

    def delete(self, user_id):
        """Remove user from store (caller already verified existence)."""
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user {0} not found".format(user_id))
            user = self._users.pop(user_id)
            del self._by_username[user.username]
            del self._by_email[user.email]

    def exists(self, user_id):
        # caller must hold self._lock
        return user_id in self._users


class _ProjectStore:
    def __init__(self, ctx):
        self._ctx = ctx
        self._lock = ctx.lock
        self._projects = {}  # id -> Project

    def create(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if not name or not name.strip():
                raise ValidationError("project name is required")
            if end_date < start_date:
                raise ValidationError("end_date cannot be before start_date")
            pid = self._ctx.next_id()
            project = Project(id=pid, name=name, start_date=start_date,
                              end_date=end_date, owner_id=owner_id,
                              description=description)
            self._projects[pid] = project
            return copy.deepcopy(project)

    def get(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project {0} not found".format(project_id))
            return copy.deepcopy(self._projects[project_id])

    def list_all(self):
        with self._lock:
            return [copy.deepcopy(p)
                    for p in sorted(self._projects.values(), key=lambda p: p.id)]

    def update(self, project_id, name=None, start_date=None, end_date=None,
               description=None):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project {0} not found".format(project_id))
            project = self._projects[project_id]
            if name is not None:
                if not name or not name.strip():
                    raise ValidationError("project name is required")
                project.name = name
            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return copy.deepcopy(project)

    def delete(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project {0} not found".format(project_id))
            del self._projects[project_id]

    def exists(self, project_id):
        # caller must hold self._lock
        return project_id in self._projects

    def get_start_date(self, project_id):
        # caller must hold self._lock
        return self._projects[project_id].start_date

    def _get_by_owner(self, owner_id):
        """Return list of live Project refs owned by owner_id.

        Caller must hold self._lock. Do NOT expose these references outside
        the lock -- they are intentionally uncopied for internal checks only.
        """
        return [p for p in self._projects.values() if p.owner_id == owner_id]


class _TaskStore:
    def __init__(self, ctx):
        self._ctx = ctx
        self._lock = ctx.lock
        self._tasks = {}          # id -> Task
        self._by_project = {}     # project_id -> set of task_ids
        self._by_assignee = {}    # user_id -> set of task_ids

    def create(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            tid = self._ctx.next_id()
            task = Task(id=tid, project_id=project_id, title=title,
                        assignee_id=assignee_id, deadline=deadline,
                        status=TaskStatus.NOT_STARTED,
                        created_at=self._ctx.now())
            self._tasks[tid] = task
            self._by_project.setdefault(project_id, set()).add(tid)
            if assignee_id is not None:
                self._by_assignee.setdefault(assignee_id, set()).add(tid)
            return copy.deepcopy(task)

    def get(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("task {0} not found".format(task_id))
            return copy.deepcopy(self._tasks[task_id])

    def list_by_project(self, project_id):
        with self._lock:
            ids = self._by_project.get(project_id, set())
            return sorted([copy.deepcopy(self._tasks[i]) for i in ids],
                          key=lambda t: t.id)

    def list_by_assignee(self, user_id):
        with self._lock:
            ids = self._by_assignee.get(user_id, set())
            return sorted([copy.deepcopy(self._tasks[i]) for i in ids],
                          key=lambda t: t.id)

    def assign(self, task_id, user_id):
        """Set assignee, updating index entries."""
        with self._lock:
            task = self._tasks[task_id]
            if task.assignee_id is not None:
                self._by_assignee.get(task.assignee_id, set()).discard(task_id)
            task.assignee_id = user_id
            self._by_assignee.setdefault(user_id, set()).add(task_id)
            return copy.deepcopy(task)

    def unassign(self, task_id):
        with self._lock:
            task = self._tasks[task_id]
            if task.assignee_id is not None:
                self._by_assignee.get(task.assignee_id, set()).discard(task_id)
                task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            self._tasks[task_id].deadline = deadline
            return copy.deepcopy(self._tasks[task_id])

    def update_status(self, task_id, status):
        with self._lock:
            task = self._tasks[task_id]
            now = self._ctx.now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)

    def delete_for_project(self, project_id):
        """Delete all tasks belonging to project_id; returns list of deleted ids."""
        with self._lock:
            ids = list(self._by_project.pop(project_id, set()))
            for tid in ids:
                task = self._tasks.pop(tid, None)
                if task and task.assignee_id is not None:
                    self._by_assignee.get(task.assignee_id, set()).discard(tid)
            return ids

    def unassign_all_for_user(self, user_id):
        """Clear all task assignments for a user being deleted."""
        with self._lock:
            ids = self._by_assignee.pop(user_id, set())
            for tid in ids:
                task = self._tasks.get(tid)
                if task:
                    task.assignee_id = None

    def exists(self, task_id):
        # caller must hold self._lock
        return task_id in self._tasks

    def get_project_id(self, task_id):
        # caller must hold self._lock
        task = self._tasks.get(task_id)
        return task.project_id if task else None

    # Raw accessors for internal use (caller must hold lock; return live
    # references -- do NOT expose these objects outside the lock).
    def get_for_project_raw(self, project_id):
        ids = self._by_project.get(project_id, set())
        return [self._tasks[i] for i in ids]

    def get_all_raw(self):
        return list(self._tasks.values())


class _MessageStore:
    def __init__(self, ctx):
        self._ctx = ctx
        self._lock = ctx.lock
        self._messages = {}       # id -> Message
        self._by_project = {}     # project_id -> list[message_id]
        self._by_task = {}        # task_id -> list[message_id]

    def post(self, author_id, body, project_id=None, task_id=None,
             attachments=None, parent_id=None):
        with self._lock:
            now = self._ctx.now()
            att_objs = []
            if attachments:
                for filename, data in attachments:
                    att_objs.append(Attachment(
                        filename=filename, size=len(data),
                        uploaded_by=author_id, uploaded_at=now
                    ))
            mid = self._ctx.next_id()
            msg = Message(id=mid, author_id=author_id, body=body,
                          project_id=project_id, task_id=task_id,
                          parent_id=parent_id, attachments=att_objs,
                          created_at=now, edited_at=None)
            self._messages[mid] = msg
            if project_id is not None:
                self._by_project.setdefault(project_id, []).append(mid)
            if task_id is not None:
                self._by_task.setdefault(task_id, []).append(mid)
            return copy.deepcopy(msg)

    def edit(self, message_id, new_body):
        with self._lock:
            msg = self._messages[message_id]
            msg.body = new_body
            msg.edited_at = self._ctx.now()
            return copy.deepcopy(msg)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            msg = self._messages[message_id]
            att = Attachment(filename=filename, size=len(data),
                             uploaded_by=uploader_id,
                             uploaded_at=self._ctx.now())
            msg.attachments.append(att)
            return copy.deepcopy(msg)

    def list_by_project(self, project_id):
        with self._lock:
            ids = self._by_project.get(project_id, [])
            result = [copy.deepcopy(self._messages[i])
                      for i in ids if i in self._messages]
            return sorted(result, key=lambda m: m.id)

    def list_by_task(self, task_id):
        with self._lock:
            ids = self._by_task.get(task_id, [])
            result = [copy.deepcopy(self._messages[i])
                      for i in ids if i in self._messages]
            return sorted(result, key=lambda m: m.id)

    def delete(self, message_id):
        with self._lock:
            msg = self._messages.pop(message_id)
            if msg.project_id is not None:
                lst = self._by_project.get(msg.project_id, [])
                if message_id in lst:
                    lst.remove(message_id)
            if msg.task_id is not None:
                lst = self._by_task.get(msg.task_id, [])
                if message_id in lst:
                    lst.remove(message_id)

    def delete_for_project(self, project_id):
        with self._lock:
            ids = self._by_project.pop(project_id, [])
            for mid in ids:
                self._messages.pop(mid, None)

    def delete_for_task(self, task_id):
        with self._lock:
            ids = self._by_task.pop(task_id, [])
            for mid in ids:
                self._messages.pop(mid, None)

    def exists(self, message_id):
        # caller must hold self._lock
        return message_id in self._messages

    def get_author(self, message_id):
        # caller must hold self._lock
        msg = self._messages.get(message_id)
        return msg.author_id if msg else None

    def has_attachments(self, message_id):
        # caller must hold self._lock
        msg = self._messages.get(message_id)
        return bool(msg and msg.attachments)


class _PerformanceStore:
    def __init__(self, ctx):
        self._ctx = ctx
        self._lock = ctx.lock
        self._ratings = {}     # id -> Rating
        self._by_ratee = {}    # ratee_id -> list[rating_id]

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            rid = self._ctx.next_id()
            rating = Rating(id=rid, rater_id=rater_id, ratee_id=ratee_id,
                            score=score, feedback=feedback, task_id=task_id,
                            created_at=self._ctx.now())
            self._ratings[rid] = rating
            self._by_ratee.setdefault(ratee_id, []).append(rid)
            return copy.deepcopy(rating)

    def get_ratings_for(self, user_id):
        with self._lock:
            ids = self._by_ratee.get(user_id, [])
            return [copy.deepcopy(self._ratings[i])
                    for i in ids if i in self._ratings]

    def delete_for_user(self, user_id):
        """Remove all ratings where user_id is either rater or ratee."""
        with self._lock:
            # Remove where user is ratee
            for rid in list(self._by_ratee.get(user_id, [])):
                self._ratings.pop(rid, None)
            self._by_ratee.pop(user_id, None)
            # Remove where user is rater (entries in other ratees' lists)
            for ratee_id in list(self._by_ratee.keys()):
                to_remove = [
                    rid for rid in self._by_ratee[ratee_id]
                    if rid in self._ratings
                    and self._ratings[rid].rater_id == user_id
                ]
                for rid in to_remove:
                    self._by_ratee[ratee_id].remove(rid)
                    self._ratings.pop(rid, None)


class _ReportStore:
    """Placeholder store; exposes _lock for the identity test."""
    def __init__(self, ctx):
        self._ctx = ctx
        self._lock = ctx.lock


# ---------------------------------------------------------------------------
# Module-level helpers
# ---------------------------------------------------------------------------

def _avg_completion_seconds(tasks):
    """Return average completion time in seconds across *tasks*, or None.

    A task is counted only if its status is COMPLETED and both started_at
    and completed_at are set.
    """
    done = [t for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None]
    if not done:
        return None
    return (sum((t.completed_at - t.started_at).total_seconds() for t in done)
            / len(done))


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------

class TeamCollaborationManager:
    """
    Thread-safe team collaboration manager.

    All public methods acquire the shared RLock before reading or mutating
    state. Methods that delegate to a store re-enter the same RLock, which
    is safe because it is an RLock (reentrant).
    """

    def __init__(self, now=None):
        if now is None:
            now = datetime.now
        ctx = _Context(now)
        self._ctx = ctx
        self._lock = ctx.lock
        self.users = _UserStore(ctx)
        self.projects = _ProjectStore(ctx)
        self.tasks = _TaskStore(ctx)
        self.messages = _MessageStore(ctx)
        self.performance = _PerformanceStore(ctx)
        self.reports = _ReportStore(ctx)

    # ------------------------------------------------------- internal guards

    def _require_user(self, user_id, kind="user"):
        """Raise NotFoundError if user_id is not registered. Caller must hold self._lock."""
        if not self.users.exists(user_id):
            raise NotFoundError("{0} {1} not found".format(kind, user_id))

    def _require_project(self, project_id):
        """Raise NotFoundError if project_id does not exist. Caller must hold self._lock."""
        if not self.projects.exists(project_id):
            raise NotFoundError("project {0} not found".format(project_id))

    def _require_task(self, task_id):
        """Raise NotFoundError if task_id does not exist. Caller must hold self._lock."""
        if not self.tasks.exists(task_id):
            raise NotFoundError("task {0} not found".format(task_id))

    def _require_message(self, message_id):
        """Raise NotFoundError if message_id does not exist. Caller must hold self._lock."""
        if not self.messages.exists(message_id):
            raise NotFoundError("message {0} not found".format(message_id))

    # ------------------------------------------------------------------ users

    def register_user(self, username, email, role=UserRole.MEMBER):
        return self.users.register(username, email, role)

    def get_user(self, user_id):
        return self.users.get(user_id)

    def list_users(self):
        return self.users.list_all()

    def update_user(self, user_id, username=None, email=None, role=None):
        return self.users.update(user_id, username=username,
                                 email=email, role=role)

    def delete_user(self, user_id):
        with self._lock:
            self._require_user(user_id)
            if self.projects._get_by_owner(user_id):
                raise ConflictError("user owns projects; delete them first")
            for task in self.tasks.list_by_assignee(user_id):
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has non-completed tasks")
            self.tasks.unassign_all_for_user(user_id)
            self.performance.delete_for_user(user_id)
            self.users.delete(user_id)

    # --------------------------------------------------------------- projects

    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            self._require_user(owner_id, "owner")
            return self.projects.create(name, start_date, end_date,
                                        owner_id, description)

    def get_project(self, project_id):
        return self.projects.get(project_id)

    def list_projects(self):
        return self.projects.list_all()

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        return self.projects.update(project_id, name=name,
                                    start_date=start_date, end_date=end_date,
                                    description=description)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            deleted_task_ids = self.tasks.delete_for_project(project_id)
            for tid in deleted_task_ids:
                self.messages.delete_for_task(tid)
            self.messages.delete_for_project(project_id)
            self.projects.delete(project_id)

    # ------------------------------------------------------------------ tasks

    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            self._require_project(project_id)
            if not title or not title.strip():
                raise ValidationError("task title is required")
            if assignee_id is not None:
                self._require_user(assignee_id, "assignee")
            if deadline is not None:
                start = self.projects.get_start_date(project_id)
                if deadline < start:
                    raise ValidationError("deadline before project start date")
            return self.tasks.create(project_id, title,
                                     assignee_id=assignee_id, deadline=deadline)

    def get_task(self, task_id):
        return self.tasks.get(task_id)

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            return self.tasks.list_by_project(project_id)

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return self.tasks.list_by_assignee(user_id)

    def assign_task(self, task_id, user_id):
        with self._lock:
            self._require_task(task_id)
            self._require_user(user_id)
            return self.tasks.assign(task_id, user_id)

    def reassign_task(self, task_id, user_id):
        return self.assign_task(task_id, user_id)

    def unassign_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            return self.tasks.unassign(task_id)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            self._require_task(task_id)
            if deadline is not None:
                proj_id = self.tasks.get_project_id(task_id)
                start = self.projects.get_start_date(proj_id)
                if deadline < start:
                    raise ValidationError("deadline before project start date")
            return self.tasks.set_deadline(task_id, deadline)

    def update_status(self, task_id, status):
        with self._lock:
            self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus instance")
            return self.tasks.update_status(task_id, status)

    # --------------------------------------------------------------- messages

    def post_message(self, author_id, body, project_id=None, task_id=None,
                     attachments=None, parent_id=None):
        with self._lock:
            # Validation order prescribed by spec
            self._require_user(author_id, "author")
            # Exactly one of project_id / task_id
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id must be provided")
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if not body.strip() and not attachments:
                raise ValidationError("body or attachments required")
            if parent_id is not None and not self.messages.exists(parent_id):
                raise NotFoundError(
                    "parent message {0} not found".format(parent_id))
            return self.messages.post(author_id, body,
                                      project_id=project_id, task_id=task_id,
                                      attachments=attachments,
                                      parent_id=parent_id)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            self._require_message(message_id)
            if self.messages.get_author(message_id) != editor_id:
                raise AuthorizationError("only the author may edit this message")
            if not new_body.strip() and not self.messages.has_attachments(message_id):
                raise ValidationError("body or attachments required")
            return self.messages.edit(message_id, new_body)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            self._require_message(message_id)
            if self.messages.get_author(message_id) != uploader_id:
                raise AuthorizationError(
                    "only the author may add attachments")
            if not filename:
                raise ValidationError("filename is required")
            return self.messages.add_attachment(message_id, uploader_id,
                                                filename, data)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            return self.messages.list_by_project(project_id)

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            return self.messages.list_by_task(task_id)

    def delete_message(self, message_id, requester_id):
        with self._lock:
            self._require_message(message_id)
            if self.messages.get_author(message_id) != requester_id:
                raise AuthorizationError(
                    "only the author may delete this message")
            self.messages.delete(message_id)

    # ------------------------------------------------------------ performance

    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self.tasks.list_by_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self.tasks.list_by_assignee(user_id)
            return _avg_completion_seconds(tasks)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            self._require_user(rater_id, "rater")
            self._require_user(ratee_id, "ratee")
            if rater_id == ratee_id:
                raise ConflictError("cannot rate yourself")
            if not (1 <= score <= 5):
                raise ValidationError("score must be 1-5 inclusive")
            if task_id is not None:
                self._require_task(task_id)
            return self.performance.submit_rating(rater_id, ratee_id, score,
                                                   feedback, task_id)

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = self.performance.get_ratings_for(user_id)
            count = len(ratings)
            average = (sum(r.score for r in ratings) / count
                       if count > 0 else 0.0)
            return {"count": count, "average": average, "ratings": ratings}

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self.tasks.list_by_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_prog = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks
                              if t.status == TaskStatus.NOT_STARTED)
            rate = completed / total if total > 0 else 0.0
            avg_time = _avg_completion_seconds(tasks)
            ratings = self.performance.get_ratings_for(user_id)
            rating_count = len(ratings)
            rating_avg = (sum(r.score for r in ratings) / rating_count
                          if rating_count > 0 else 0.0)
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_prog,
                "not_started_tasks": not_started,
                "completion_rate": rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_avg,
            }

    # ---------------------------------------------------------------- reports

    def project_progress_report(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks = self.tasks.get_for_project_raw(project_id)
            now = self._ctx.now()
            total = len(tasks)
            status_counts = {s.value: 0 for s in TaskStatus}
            overdue = 0
            per_assignee = {}
            for t in tasks:
                status_counts[t.status.value] += 1
                if (t.deadline is not None
                        and t.deadline < now
                        and t.status != TaskStatus.COMPLETED):
                    overdue += 1
                if t.assignee_id is not None:
                    if t.assignee_id not in per_assignee:
                        per_assignee[t.assignee_id] = {
                            s.value: 0 for s in TaskStatus
                        }
                    per_assignee[t.assignee_id][t.status.value] += 1
            completion_rate = (
                status_counts[TaskStatus.COMPLETED.value] / total
                if total > 0 else 0.0
            )
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
            if project_id is not None:
                all_tasks = self.tasks.get_for_project_raw(project_id)
            else:
                all_tasks = self.tasks.get_all_raw()
            # Aggregate per assignee
            user_data = {}
            for t in all_tasks:
                if t.assignee_id is None:
                    continue
                if t.assignee_id not in user_data:
                    user_data[t.assignee_id] = {
                        "total": 0, "completed": 0,
                        "in_progress": 0, "not_started": 0
                    }
                d = user_data[t.assignee_id]
                d["total"] += 1
                if t.status == TaskStatus.COMPLETED:
                    d["completed"] += 1
                elif t.status == TaskStatus.IN_PROGRESS:
                    d["in_progress"] += 1
                else:
                    d["not_started"] += 1
            columns = ["user_id", "total_tasks", "completed_tasks",
                       "in_progress_tasks", "not_started_tasks",
                       "completion_rate"]
            rows = []
            for uid, d in user_data.items():
                rate = (d["completed"] / d["total"] if d["total"] > 0 else 0.0)
                rows.append({
                    "user_id": uid,
                    "total_tasks": d["total"],
                    "completed_tasks": d["completed"],
                    "in_progress_tasks": d["in_progress"],
                    "not_started_tasks": d["not_started"],
                    "completion_rate": rate,
                })
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "rows": rows,
                "columns": columns,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self.tasks.list_by_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks
                            if t.status == TaskStatus.COMPLETED)
            task_list = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "tasks": task_list,
            }

    def export_report(self, report, fmt):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("fmt must be a ReportFormat instance")
            if fmt == ReportFormat.CSV:
                return self._to_csv(report)
            return self._to_pdf(report)

    # --------------------------------------------------------- export helpers

    def _to_csv(self, report):
        buf = io.StringIO()
        writer = csv.writer(buf)
        rtype = report.get("report_type")
        if rtype == ReportType.TEAM_PERFORMANCE.value:
            columns = report.get("columns", [])
            writer.writerow(columns)
            for row in report.get("rows", []):
                writer.writerow([row.get(c, "") for c in columns])
        else:
            # Generic field/value table
            writer.writerow(["field", "value"])
            for k, v in report.items():
                writer.writerow([k, str(v)])
        return buf.getvalue()

    def _to_pdf(self, report):
        """Build a minimal, structurally valid single-page PDF."""
        # Render report as a short text line (escaping PDF special chars)
        summary = "report_type={0}".format(report.get("report_type", ""))
        summary = (summary.replace("\\", "\\\\")
                          .replace("(", "\\(")
                          .replace(")", "\\)"))
        content_stream = (
            "BT /F1 12 Tf 50 700 Td ({0}) Tj ET".format(summary)
        ).encode("ascii")

        obj1 = b"1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n"
        obj2 = b"2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj\n"
        obj3 = (
            b"3 0 obj\n<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792]"
            b" /Contents 4 0 R"
            b" /Resources << /Font << /F1 5 0 R >> >> >>\nendobj\n"
        )
        obj4 = (
            b"4 0 obj\n<< /Length "
            + str(len(content_stream)).encode()
            + b" >>\nstream\n"
            + content_stream
            + b"\nendstream\nendobj\n"
        )
        obj5 = (
            b"5 0 obj\n<< /Type /Font /Subtype /Type1"
            b" /BaseFont /Helvetica >>\nendobj\n"
        )

        header = b"%PDF-1.4\n"
        objects = [obj1, obj2, obj3, obj4, obj5]

        body = b""
        offsets = []
        pos = len(header)
        for obj in objects:
            offsets.append(pos)
            body += obj
            pos += len(obj)

        xref_offset = len(header) + len(body)
        n = len(objects) + 1  # includes free entry 0

        xref = ("xref\n0 {0}\n".format(n)).encode()
        xref += _PDF_XREF_FREE_HEAD
        for off in offsets:
            xref += ("{0:010d} 00000 n \n".format(off)).encode()

        trailer = (
            "trailer\n<< /Size {0} /Root 1 0 R >>\n"
            "startxref\n{1}\n%%EOF\n".format(n, xref_offset)
        ).encode()

        return header + body + xref + trailer
